<template>
    <main class="w-50 m-auto">
        <form>
            <div style="text-align:center">
                <img class="mb-3 mt-3" src="../assets/img/lock.svg" alt="" width="80">
                <h1 class="h4 mb-4">用户登录</h1>
            </div>
            <div class="mb-4">
                <input v-model="username" type="text" class="form-control active" id="name" placeholder="请输入用户名"
                    required="">
            </div>
            <div class="mb-4">
                <input v-model="password" type="password" class="form-control" placeholder="请输入密码">
            </div>
            <button v-on:click.prevent="login" class="w-100 btn btn-primary" type="submit">登录</button>
        </form>
    </main>
</template>

<script>
export default {
    data() {
        return {
            username: "",
            password: ""
        }
    },
    methods: {
        login() {
            this.axios.post('http://localhost:3001/api/login', {
                username: this.username,
                password: this.password
            })
                .then((response) => {
                    if (response.data.data.code == 200) {
                       sessionStorage.setItem('token',response.data.data.data.token)
                    //    console.log(response.data.data.data.router)
                    // 本地存储里的item只能是字符串，而我们收到的是数组，需要转成JSON字符串
                    //    sessionStorage.setItem('router',response.data.data.data.router)
                    // 使用JSON.stringify转成json格式的字符串
                       sessionStorage.setItem('router',JSON.stringify(response.data.data.data.router))
                       // 当用户是admin时跳转到留言管理页面
                       console.log('登录成功，用户名为:', this.username);
                       console.log('准备跳转到:', this.username === 'admin' ? "/admin" : "/messageboard");
                       if (this.username === 'admin') {
                           this.$router.push("/admin")
                       } else {
                           this.$router.push("/messageboard")
                       }
                    }
                    else {
                        let message=response.data.data.message
                        alert(message)
                    }
                })
        }
    }
}
</script>

